import React, { useState, useEffect, useContext, useRef, useCallback } from 'react';
import { chatAPI, authAPI } from '../services/api';
import { AuthContext } from '../context/AuthContext';
import io from 'socket.io-client';

// SVG Icons
const SearchIcon = () => (
  <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" fill="currentColor" className="search-icon" viewBox="0 0 16 16">
    <path d="M11.742 10.344a6.5 6.5 0 1 0-1.397 1.398h-.001c.03.04.062.078.098.115l3.85 3.85a1 1 0 0 0 1.415-1.414l-3.85-3.85a1.007 1.007 0 0 0-.115-.1zM12 6.5a5.5 5.5 0 1 1-11 0 5.5 5.5 0 0 1 11 0z"/>
  </svg>
);

const SendIcon = () => (
  <svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" fill="currentColor" viewBox="0 0 16 16">
    <path d="M15.854.146a.5.5 0 0 1 .11.54l-5.819 14.547a.75.75 0 0 1-1.329.124l-3.178-4.995L.643 7.184a.75.75 0 0 1 .124-1.33L15.314.037a.5.5 0 0 1 .54.11ZM6.636 10.07l2.761 4.338L14.13 2.576 6.636 10.07Zm6.787-8.201L1.591 6.602l4.339 2.76 7.494-7.493Z"/>
  </svg>
);

const ChatPage = () => {
  const { user } = useContext(AuthContext);
  const [users, setUsers] = useState([]);
  const [selectedUser, setSelectedUser] = useState(null);
  const [messages, setMessages] = useState([]);
  const [newMessage, setNewMessage] = useState('');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [isChatbot, setIsChatbot] = useState(false);
  const [chatbotLoading, setChatbotLoading] = useState(false);
  const [unreadCounts, setUnreadCounts] = useState({});
  const [notificationText, setNotificationText] = useState('');
  const [searchTerm, setSearchTerm] = useState('');
  const socket = useRef(null);
  const messagesEndRef = useRef(null);
  const selectedUserRef = useRef(null);
  const isChatbotRef = useRef(false);
  const usersRef = useRef([]);

  const handleReceiveMessage = useCallback((data) => {
    const activeUserId = selectedUserRef.current?._id;
    const isChatbotActive = isChatbotRef.current;
    const isActiveChat = data.senderId === activeUserId && !isChatbotActive;

    if (isActiveChat) {
      setMessages((prev) => [...prev, data]);
      return;
    }

    setUnreadCounts((prev) => ({
      ...prev,
      [data.senderId]: (prev[data.senderId] || 0) + 1,
    }));

    const sender = usersRef.current.find((item) => item._id === data.senderId);
    const senderName = sender?.name || 'New message';
    setNotificationText(`New message from ${senderName}`);
  }, []);

  useEffect(() => {
    socket.current = io('http://localhost:5000', {
      auth: {
        token: sessionStorage.getItem('token') || localStorage.getItem('token'),
      },
    });

    socket.current.emit('user_join', user?._id);
    socket.current.on('receive_message', handleReceiveMessage);

    return () => {
      socket.current.off('receive_message', handleReceiveMessage);
      socket.current.disconnect();
    };
  }, [user, handleReceiveMessage]);

  useEffect(() => {
    selectedUserRef.current = selectedUser;
    isChatbotRef.current = isChatbot;
  }, [selectedUser, isChatbot]);

  useEffect(() => {
    usersRef.current = users;
  }, [users]);

  useEffect(() => {
    if (!notificationText) return undefined;
    const timer = setTimeout(() => setNotificationText(''), 3000);
    return () => clearTimeout(timer);
  }, [notificationText]);

  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages]);

  useEffect(() => {
    fetchUsers();
  }, []);

  const filteredUsers = users.filter((staffMember) => {
    const query = searchTerm.trim().toLowerCase();
    if (!query) return true;
    return (
      staffMember.name?.toLowerCase().includes(query) ||
      staffMember.subject?.toLowerCase().includes(query)
    );
  });

  const fetchUsers = async () => {
    try {
      const res = await authAPI.getAllStaff();
      const staff = res.data.staff || [];
      const chatbot = { _id: 'chatbot', name: 'AI Assistant', subject: 'Instant academic support' };
      setUsers([chatbot, ...staff]);
    } catch (err) {
      setError(err.response?.data?.error || 'Failed to fetch users');
    }
  };

  const handleSelectUser = async (staffMember) => {
    setSelectedUser(staffMember);
    setIsChatbot(staffMember._id === 'chatbot');
    setUnreadCounts((prev) => ({ ...prev, [staffMember._id]: 0 }));

    if (staffMember._id === 'chatbot') {
      setMessages([
        {
          senderId: 'chatbot',
          senderName: 'AI Assistant',
          message: "Hello. I'm here to help with academic questions, explanations, and quick guidance. If you need subject-specific support, you can also continue with a staff member.",
          timestamp: new Date().toISOString(),
        },
      ]);
      setLoading(false);
      return;
    }

    setLoading(true);
    try {
      const res = await chatAPI.getChatHistory(staffMember._id);
      setMessages(res.data.messages || []);
    } catch (err) {
      setError(err.response?.data?.error || 'Failed to fetch chat history');
    } finally {
      setLoading(false);
    }
  };

  const handleSendMessage = async () => {
    if (!newMessage.trim() || !selectedUser) return;

    if (isChatbot) {
      const userMessage = {
        senderId: user._id,
        senderName: user.name,
        message: newMessage.trim(),
        timestamp: new Date().toISOString(),
      };
      setMessages((prev) => [...prev, userMessage]);
      setChatbotLoading(true);

      try {
        const response = await chatAPI.getChatbotResponse(newMessage.trim());
        setMessages((prev) => [
          ...prev,
          {
            senderId: 'chatbot',
            senderName: 'AI Assistant',
            message: response.data.response,
            timestamp: new Date().toISOString(),
          },
        ]);
      } catch (err) {
        setMessages((prev) => [
          ...prev,
          {
            senderId: 'chatbot',
            senderName: 'AI Assistant',
            message:
              err.response?.data?.response ||
              err.response?.data?.error ||
              'The assistant is temporarily unavailable. Please continue with a staff member.',
            timestamp: new Date().toISOString(),
          },
        ]);
      } finally {
        setChatbotLoading(false);
      }

      setNewMessage('');
      return;
    }

    try {
      await chatAPI.sendMessage({
        receiverId: selectedUser._id,
        message: newMessage.trim(),
      });

      socket.current.emit('send_message', {
        senderId: user._id,
        receiverId: selectedUser._id,
        message: newMessage.trim(),
      });

      setMessages((prev) => [
        ...prev,
        {
          senderId: user._id,
          senderName: user.name,
          message: newMessage.trim(),
          timestamp: new Date().toISOString(),
        },
      ]);
      setNewMessage('');
    } catch (err) {
      setError(err.response?.data?.error || 'Failed to send message');
    }
  };

  const formatTime = (timestamp) =>
    new Date(timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });

  const getInitials = (name) => {
    if (!name) return '?';
    // For AI Assistant, we can return an icon or specific initials
    if (name === 'AI Assistant') return 'AI';
    return name.charAt(0).toUpperCase();
  };

  return (
    <div className="container-fluid py-4 min-vh-100 d-flex flex-column">
      <div className="portal-page-header">
        <span className="portal-page-kicker">Messages</span>
        <h1 className="portal-page-title">Student Communication</h1>
        <p className="portal-page-subtitle">
          Start a conversation with staff members or use the AI assistant for quick help.
        </p>
      </div>

      {error && (
        <div className="alert alert-danger alert-dismissible fade show" role="alert">
          {error}
          <button type="button" className="btn-close" onClick={() => setError('')}></button>
        </div>
      )}

      {notificationText && (
        <div className="position-fixed top-0 end-0 p-3" style={{ zIndex: 1080 }}>
          <div className="alert alert-info shadow-sm mb-0 rounded-4" role="alert">
            {notificationText}
          </div>
        </div>
      )}

      <div className="premium-chat-shell row m-0">
        <div className="col-md-4 col-lg-3 premium-chat-sidebar p-0">
          <div className="premium-chat-toolbar">
            <h4 className="mb-0 fw-bold">Contacts</h4>
            <div className="premium-search-box">
              <SearchIcon />
              <input
                type="text"
                className="form-control premium-search-input"
                placeholder="Search resources..."
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
              />
            </div>
          </div>

          <div className="premium-chat-list">
            {filteredUsers.length === 0 ? (
              <div className="portal-empty-state">No staff members are available right now.</div>
            ) : (
              filteredUsers.map((staffMember) => {
                const isAI = staffMember._id === 'chatbot';
                return (
                  <button
                    key={staffMember._id}
                    className={`premium-chat-user ${selectedUser?._id === staffMember._id ? 'active' : ''}`}
                    onClick={() => handleSelectUser(staffMember)}
                  >
                    <div className={`chat-avatar ${isAI ? 'ai-avatar' : ''}`}>
                       {getInitials(staffMember.name)}
                    </div>
                    <div className="flex-grow-1 min-w-0" style={{ overflow: 'hidden' }}>
                      <div className="d-flex justify-content-between align-items-center mb-1">
                        <span className={`fw-bold text-truncate ${isAI ? 'text-success' : ''}`} style={{ maxWidth: '80%' }}>
                          {staffMember.name}
                        </span>
                        {unreadCounts[staffMember._id] > 0 && (
                          <span className="badge bg-danger rounded-pill">{unreadCounts[staffMember._id]}</span>
                        )}
                      </div>
                      <div className="text-muted small text-truncate">{staffMember.subject || 'Staff support'}</div>
                    </div>
                  </button>
                );
              })
            )}
          </div>
        </div>

        <div className="col-md-8 col-lg-9 premium-chat-main p-0">
          {selectedUser ? (
            <>
              <div className="premium-chat-header">
                <div className="d-flex align-items-center gap-3">
                  <div className={`chat-avatar ${isChatbot ? 'ai-avatar' : ''}`}>
                     {getInitials(selectedUser.name)}
                  </div>
                  <div>
                    <h5 className="mb-0 fw-bold">{selectedUser.name}</h5>
                    <small className="text-muted">{selectedUser.subject}</small>
                  </div>
                </div>
                <div className="d-flex align-items-center gap-2">
                  <span className={`badge ${isChatbot ? 'bg-success text-white' : 'bg-success-subtle text-success'} rounded-pill px-3 py-2 d-flex align-items-center`}>
                    {!isChatbot && <span className="d-inline-block bg-success rounded-circle me-2" style={{width: '6px', height: '6px'}}></span>}
                    {isChatbot ? 'AI Active' : 'Active'}
                  </span>
                </div>
              </div>

              <div className="premium-chat-messages">
                {loading ? (
                  <div className="d-flex justify-content-center align-items-center h-100">
                    <div className="spinner-border text-primary" role="status">
                      <span className="visually-hidden">Loading...</span>
                    </div>
                  </div>
                ) : messages.length === 0 ? (
                  <div className="d-flex flex-column justify-content-center align-items-center h-100 text-muted">
                    <div className="chat-avatar mb-3" style={{width: '64px', height: '64px', fontSize: '1.5rem', background: 'var(--bg-secondary)', color: 'var(--text-muted)', boxShadow: 'none'}}>
                      {getInitials(selectedUser.name)}
                    </div>
                    <h5>Start the conversation with {selectedUser.name.split(' ')[0]}</h5>
                    <p>Send a message below to begin.</p>
                  </div>
                ) : (
                  messages.map((msg, index) => {
                    const isOutgoing = msg.senderId === user._id;
                    const isAiMsg = msg.senderId === 'chatbot';
                    let wrapperClass = isOutgoing ? 'outgoing' : 'incoming';
                    if (isAiMsg) wrapperClass = 'ai-message';

                    return (
                      <div key={index} className={`message-wrapper ${wrapperClass}`}>
                        <div className="d-flex flex-column" style={{ alignItems: isOutgoing ? 'flex-end' : 'flex-start' }}>
                          <div className="premium-message">
                            {msg.message}
                          </div>
                          <span className="premium-message-time">{formatTime(msg.timestamp)}</span>
                        </div>
                      </div>
                    );
                  })
                )}

                {chatbotLoading && (
                  <div className="message-wrapper ai-message">
                    <div className="d-flex flex-column" style={{ alignItems: 'flex-start' }}>
                      <div className="premium-message d-flex gap-2 align-items-center">
                        <div className="spinner-grow spinner-grow-sm text-success" role="status"></div>
                        <div className="spinner-grow spinner-grow-sm text-success" role="status" style={{animationDelay: '0.2s'}}></div>
                        <div className="spinner-grow spinner-grow-sm text-success" role="status" style={{animationDelay: '0.4s'}}></div>
                      </div>
                    </div>
                  </div>
                )}

                <div ref={messagesEndRef} />
              </div>

              <div className="premium-chat-input-area">
                <div className="premium-input-wrapper">
                  <input
                    type="text"
                    className="premium-message-input"
                    placeholder="Type your message..."
                    value={newMessage}
                    onChange={(e) => setNewMessage(e.target.value)}
                    onKeyDown={(e) => e.key === 'Enter' && handleSendMessage()}
                  />
                  <button 
                    className="premium-send-btn" 
                    type="button" 
                    onClick={handleSendMessage}
                    disabled={!newMessage.trim() || chatbotLoading}
                  >
                    <SendIcon />
                  </button>
                </div>
              </div>
            </>
          ) : (
            <div className="d-flex flex-column justify-content-center align-items-center h-100">
               <div className="p-4 rounded-circle mb-3 text-muted" style={{ background: 'var(--bg-surface-solid)' }}>
                 <svg xmlns="http://www.w3.org/2000/svg" width="48" height="48" fill="currentColor" viewBox="0 0 16 16">
                   <path d="M2 1a1 1 0 0 0-1 1v8a1 1 0 0 0 1 1h9.586a2 2 0 0 1 1.414.586l2 2V2a1 1 0 0 0-1-1H2zm12-1a2 2 0 0 1 2 2v12.793a.5.5 0 0 1-.854.353l-2.853-2.853a1 1 0 0 0-.707-.293H2a2 2 0 0 1-2-2V2a2 2 0 0 1 2-2h12z"/>
                   <path d="M5 6a1 1 0 1 1-2 0 1 1 0 0 1 2 0zm4 0a1 1 0 1 1-2 0 1 1 0 0 1 2 0zm4 0a1 1 0 1 1-2 0 1 1 0 0 1 2 0z"/>
                 </svg>
               </div>
               <h4 className="fw-bold">Your Messages</h4>
               <p className="text-muted">Select a staff member or AI Assistant to open the conversation.</p>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default ChatPage;
